object_base[442] = createObject({
    b_i: 442,
    b_t: BASE_TYPE.OBJECT,
    name: 'Treasure Chest',
    type: OBJECT_TYPE.COOKING,
    img: {
        sheet: IMAGE_SHEET.FIRST,
        x: 3,
        y: 14
    },
    params: {
        desc: 'Chest usually contains a key'
    },
    activities: [
        ACTIVITIES.OPEN,
        ACTIVITIES.INSPECT
    ],
    fn: {
        open: function (a, b) {
            if (players[0].temp.busy)
                return !1;
            players[0].temp.busy = !0;
            setTimeout(function () {
                players[0].temp.busy = !1;
            }, 1000);
            if (a.params &&
                'undefined' != typeof a.params.contains_id &&
                0 < Inventory.get_item_count_include_pet(b, a.params.contains_id))
                return addChatText(_te('I already have one \'{item_name}\'', {
                    item_name: item_base[a.params.contains_id].name
                }), null, COLOR.PINK, 'exists'),
                    !1;
            needsProximity(b, a, 1, !0) &&
                Player.open_treasure_chest(a.id);
            return !0;
        }
    }
}, 1);
var consumes_all_keys = [
    {
        id: 1057,
        count: 1
    },
    {
        id: 1058,
        count: 1
    },
    {
        id: 1059,
        count: 1
    }
], treasure_chest_script = {
    use: function (a, b) {
        selected = obj_g(a);
        if (needsProximity(b, a, 1, !0)) {
            var d = Skills.can_perform(b, a.id);
            d.status ? (addChatText(_ti('You attempt to open the chest...'), null, COLOR.YELLOW, 'attempt'),
                Socket.send('use_skill', {
                    target_id: a.id
                })) : addChatText(_te(d.reason), null, COLOR.PINK, 'cannot');
        }
        return !0;
    }
};
