object_base[555] = createObject({
    b_i: 555,
    b_t: BASE_TYPE.OBJECT,
    name: 'Loot Crate',
    type: OBJECT_TYPE.DUMMY,
    img: {
        sheet: IMAGE_SHEET.POTS_CRATES,
        x: 8,
        y: 7
    },
    activities: [
        ACTIVITIES.OPEN,
        ACTIVITIES.DESTROY,
        ACTIVITIES.INSPECT
    ],
    fn: {
        open: function (a, b) {
            if (players[0].temp.busy)
                return !1;
            players[0].temp.busy = !0;
            setTimeout(function () {
                players[0].temp.busy = !1;
            }, 100);
            if (Inventory.is_full(b))
                return addChatText(_te('Your inventory is full!'), null, COLOR.PINK, 'cannot'),
                    !1;
            needsProximity(b, a, 1, !0) &&
                (Socket.send('loot_crate', {
                    map: a.map,
                    i: a.i,
                    j: a.j
                }),
                    LootCrate.remove(a.i, a.j, a.map));
            return !0;
        },
        destroy: function (a, b) {
            if (players[0].temp.busy)
                return !1;
            players[0].temp.busy = !0;
            setTimeout(function () {
                players[0].temp.busy = !1;
            }, 100);
            needsProximity(b, a, 1, !0) &&
                (Socket.send('loot_crate', {
                    map: a.map,
                    i: a.i,
                    j: a.j,
                    destroy: !0
                }),
                    LootCrate.remove(a.i, a.j, a.map));
            return !0;
        }
    }
}, 1);
