var water_tank_description = function (a) {
    return _tit('contains {amount} out of {total} units of water', {
        amount: a.params.water_current ||
            0,
        total: a.base().params.water
    });
}, water_tank_use = function (a, b) {
    if (needsProximity(b, a, 1, !0) && my_map(current_map)) {
        if (!Inventory.get_watering_can_id(players[0]))
            return Timers.set('use_water_tank', null_function, 250),
                addChatText(_te('You need a watering can!'), null, COLOR.PINK, 'cannot');
        Timers.running('use_water_tank') ||
            (Timers.set('use_water_tank', null_function, 1100),
                Socket.send('carpentry', {
                    sub: 'use_water_tank',
                    position: {
                        i: a.i - (Player.is_player_map(current_map) ? 10 : 0),
                        j: a.j - (Player.is_player_map(current_map) ? 10 : 0)
                    }
                }));
    }
};
